const response = await Memento.plugins.checkin.getCheckinItems();

if (!response.success) {
  const result = { success: false, message: '获取签到项目失败' };
  setResult(result);
  return result;
}

const result = {
  success: true,
  count: response.data.length,
  items: response.data.map(i => ({
    id: i.id,
    name: i.name,
    group: i.group,
    consecutiveDays: i.consecutiveDays,
    isCheckedToday: i.isCheckedToday,
    lastCheckinDate: i.lastCheckinDate
  }))
};

setResult(result);
return result;

const itemsResponse = await Memento.plugins.checkin.getCheckinItems();

if (!itemsResponse.success) {
  const result = { success: false, message: '获取签到项目失败' };
  setResult(result);
  return result;
}

const item = itemsResponse.data.find(i => i.name.includes('早起'));

if (!item) {
  const result = { success: false, message: '未找到"早起"签到项目' };
  setResult(result);
  return result;
}

const response = await Memento.plugins.checkin.checkin({ itemId: item.id });

const result = {
  success: response.success,
  message: response.data.message,
  consecutiveDays: response.data.consecutiveDays,
  checkinTime: response.data.checkinTime
};

setResult(result);
return result;

const stats = await Memento.plugins.checkin.getStats();

const result = {
  totalItems: stats.totalItems,
  todayCheckins: stats.todayCheckins,
  totalCheckins: stats.totalCheckins,
  completionRate: stats.completionRate
};

setResult(result);
return result;

const response = await Memento.plugins.checkin.createCheckinItem({
  name: '每日学习',
  description: '每天学习新知识',
  group: '学习'
});

const result = {
  success: response.success,
  message: response.message,
  item: response.item
};

setResult(result);
return result;
